// ── STORAGE ───────────────────────────────────────────────────────────────────
async function sget(key) {
  try { const r = await window.storage.get(key, true); return r ? JSON.parse(r.value) : null; } catch { return null; }
}
async function sset(key, val) {
  try { await window.storage.set(key, JSON.stringify(val), true); } catch {}
}

const SESSION_KEY = "op-transit-session";
const saveSession  = p  => { try { localStorage.setItem(SESSION_KEY, JSON.stringify(p)); } catch {} };
const loadSession  = () => { try { const s = localStorage.getItem(SESSION_KEY); return s ? JSON.parse(s) : null; } catch { return null; } };
const clearSession = () => { try { localStorage.removeItem(SESSION_KEY); } catch {} };

// ── SMALL UI ──────────────────────────────────────────────────────────────────
const Label = ({ children, color = C.accent }) => (
  <span style={{ padding: "1px 7px", fontSize: 9, fontFamily: "'Share Tech Mono'", background: color + "18", color, border: `1px solid ${color}33`, borderRadius: 2, letterSpacing: 1 }}>{children}</span>
);
const SectionTitle = ({ children, color }) => (
  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14 }}>
    <div style={{ width: 3, height: 16, background: color || C.accent, borderRadius: 1 }} />
    <span style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 13, letterSpacing: 3, color: color || C.accent, textTransform: "uppercase" }}>{children}</span>
  </div>
);
const Card = ({ children, style }) => (
  <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 4, ...style }}>{children}</div>
);
const Btn = ({ children, onClick, color = C.accent, outline, disabled, style }) => (
  <button onClick={onClick} disabled={disabled} style={{ padding: "10px 16px", background: outline ? "none" : (disabled ? C.border : color), border: `1px solid ${outline ? C.border : "transparent"}`, borderRadius: 4, color: outline ? C.muted : (disabled ? C.muted : "#fff"), fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14, letterSpacing: 1, cursor: disabled ? "not-allowed" : "pointer", transition: "all 0.15s", ...style }}>{children}</button>
);
const inputStyle  = { width: "100%", background: C.surface, border: `1px solid ${C.border}`, borderRadius: 4, padding: "10px 12px", color: C.text, fontFamily: "'Barlow'", fontSize: 13, outline: "none" };
const selectStyle = { ...inputStyle, cursor: "pointer" };

const Toast = ({ msg, color }) => (
  <div style={{ position: "fixed", top: 64, left: "50%", transform: "translateX(-50%)", background: color + "22", border: `1px solid ${color}60`, borderRadius: 6, padding: "8px 16px", zIndex: 999, fontFamily: "'Barlow'", fontSize: 13, color, animation: "slideFromTop 0.25s ease", whiteSpace: "nowrap" }}>{msg}</div>
);

// ── ANNONCE BANNER ────────────────────────────────────────────────────────────
function AnnounceBanner({ announce, onDismiss }) {
  if (!announce?.text) return null;
  return (
    <div style={{ background: C.danger + "15", borderBottom: `1px solid ${C.danger}50`, padding: "10px 16px", display: "flex", alignItems: "center", gap: 10, animation: "slideFromTop 0.3s ease" }}>
      <span style={{ fontSize: 16, flexShrink: 0 }}>📢</span>
      <div style={{ flex: 1 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.danger, letterSpacing: 1, marginBottom: 2 }}>ANNONCE ADMIN</div>
        <div style={{ fontFamily: "'Barlow'", fontSize: 13, color: C.text, lineHeight: 1.4 }}>{announce.text}</div>
      </div>
      <button onClick={onDismiss} style={{ background: "none", border: "none", color: C.muted, cursor: "pointer", fontSize: 16, flexShrink: 0 }}>✕</button>
    </div>
  );
}

