// ── INSCRIPTION ───────────────────────────────────────────────────────────────
function InscriptionScreen({ onRegister }) {
  const [step, setStep]           = useState(1);
  const [nom, setNom]             = useState("");
  const [pseudo, setPseudo]       = useState("");
  const [faction, setFaction]     = useState(null);
  const [adminCode, setAdminCode] = useState("");
  const [adminError, setAdminError] = useState("");
  const [showAdmin, setShowAdmin] = useState(false);

  const handleFinish = () => {
    const isAdmin = adminCode.toUpperCase() === ADMIN_CODE;
    if (adminCode && !isAdmin) { setAdminError("Code incorrect"); return; }
    onRegister({ nom: nom.trim(), pseudo: pseudo.trim() || "Joueur", faction, isAdmin });
  };

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "center", padding: 24, animation: "fadeIn 0.4s ease" }}>
      <div style={{ textAlign: "center", marginBottom: 36 }}>
        <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 34, letterSpacing: 4, color: C.accent }}>OP TRANSIT</div>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, letterSpacing: 3 }}>COMPANION · SAISON 2026</div>
      </div>

      {step === 1 && (
        <div style={{ animation: "slideUp 0.3s ease" }}>
          <SectionTitle>Identification</SectionTitle>
          <div style={{ display: "flex", flexDirection: "column", gap: 12, marginBottom: 20 }}>
            <div>
              <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, letterSpacing: 1, marginBottom: 6 }}>PRÉNOM / NOM</div>
              <input style={inputStyle} placeholder="Ex: Jean Dupont" value={nom} onChange={e => setNom(e.target.value)} />
            </div>
            <div>
              <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, letterSpacing: 1, marginBottom: 6 }}>CALLSIGN (pseudo)</div>
              <input style={inputStyle} placeholder="Ex: Ghost" value={pseudo} onChange={e => setPseudo(e.target.value)} onKeyDown={e => e.key === "Enter" && pseudo.trim() && setStep(2)} />
            </div>
          </div>
          <Btn onClick={() => setStep(2)} disabled={!pseudo.trim()} style={{ width: "100%" }}>CONTINUER →</Btn>
        </div>
      )}

      {step === 2 && (
        <div style={{ animation: "slideUp 0.3s ease" }}>
          <SectionTitle>Choisis ta faction</SectionTitle>
          <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 20 }}>
            {[
              { id: "DNRED",  label: "D.N.R.E.D",      desc: "Forces spéciales — localiser et extraire Don Pipo",         color: C.drned,  icon: "🛡" },
              { id: "CARTEL", label: "CARTEL DEL PASO", desc: "Paramilitaires — défendre la base et neutraliser la DNRED", color: C.cartel, icon: "☠️" },
            ].map(f => (
              <div key={f.id} onClick={() => setFaction(f.id)} style={{ background: faction === f.id ? f.color + "15" : C.card, border: `2px solid ${faction === f.id ? f.color : C.border}`, borderRadius: 6, padding: "16px", cursor: "pointer", transition: "all 0.2s" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 4 }}>
                  <span style={{ fontSize: 22 }}>{f.icon}</span>
                  <span style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 18, color: f.color, letterSpacing: 2 }}>{f.label}</span>
                </div>
                <div style={{ fontFamily: "'Barlow'", fontSize: 12, color: C.muted }}>{f.desc}</div>
              </div>
            ))}
          </div>
          <div style={{ marginBottom: 16 }}>
            <div onClick={() => setShowAdmin(!showAdmin)} style={{ cursor: "pointer", marginBottom: showAdmin ? 8 : 0 }}>
              <span style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, letterSpacing: 1 }}>{showAdmin ? "▼" : "▶"} CODE ADMIN (optionnel)</span>
            </div>
            {showAdmin && (
              <div style={{ animation: "slideUp 0.2s ease" }}>
                <input style={{ ...inputStyle, fontFamily: "'Share Tech Mono'", letterSpacing: 3, borderColor: adminError ? C.red : C.border }} placeholder="••••••••••••" type="password" value={adminCode} onChange={e => { setAdminCode(e.target.value); setAdminError(""); }} />
                {adminError && <div style={{ color: C.red, fontSize: 11, marginTop: 4 }}>{adminError}</div>}
              </div>
            )}
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn outline onClick={() => setStep(1)} style={{ flex: 1 }}>← RETOUR</Btn>
            <Btn onClick={handleFinish} disabled={!faction} color={faction === "DNRED" ? C.drned : C.cartel} style={{ flex: 2 }}>REJOINDRE L'OP ✓</Btn>
          </div>
        </div>
      )}
    </div>
  );
}

// ── HOME ──────────────────────────────────────────────────────────────────────
function HomeScreen({ player, timerState }) {
  const fc = player.faction === "DNRED" ? C.drned : C.cartel;
  let remaining = timerState.remaining;
  if (timerState.running && timerState.startedAt) {
    remaining = Math.max(0, timerState.remaining - Math.floor((Date.now() - timerState.startedAt) / 1000));
  }
  const mm  = String(Math.floor(remaining / 60)).padStart(2, "0");
  const ss  = String(remaining % 60).padStart(2, "0");
  const pct = Math.round(((45 * 60 - remaining) / (45 * 60)) * 100);

  return (
    <div style={{ padding: "0 0 20px", animation: "fadeIn 0.4s ease" }}>
      <div style={{ background: "#0d1117", borderBottom: `1px solid ${C.border}`, borderTop: `2px solid ${fc}`, padding: "20px 16px", marginBottom: 12 }}>
        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
          <div>
            <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, letterSpacing: 2, marginBottom: 4 }}>OPÉRATEUR</div>
            <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 22, letterSpacing: 2 }}>{player.pseudo.toUpperCase()}</div>
            <div style={{ display: "flex", gap: 6, marginTop: 4 }}>
              <Label color={fc}>{player.faction === "DNRED" ? "D.N.R.E.D" : "CARTEL DEL PASO"}</Label>
              {player.isAdmin && <Label color={C.admin}>⭐ ADMIN</Label>}
            </div>
          </div>
          <div style={{ fontFamily: "'Share Tech Mono'", color: timerState.running ? C.green : C.muted, fontSize: 10 }}>
            <span style={{ animation: timerState.running ? "blink 1s infinite" : "none", display: "inline-block", marginRight: 4 }}>●</span>
            {timerState.running ? "EN JEU" : "EN ATTENTE"}
          </div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 52, color: remaining === 0 ? C.red : remaining < 300 ? C.danger : C.accent, letterSpacing: 8, lineHeight: 1, animation: remaining < 60 && timerState.running ? "pulse 1s infinite" : "none" }}>{mm}:{ss}</div>
          <div style={{ fontFamily: "'Barlow'", fontSize: 10, color: C.muted, letterSpacing: 2, marginTop: 4 }}>{remaining === 0 ? "TEMPS ÉCOULÉ" : "TEMPS RESTANT"}</div>
          <div style={{ height: 3, background: C.border, borderRadius: 2, marginTop: 10 }}>
            <div style={{ height: "100%", width: `${pct}%`, background: remaining < 300 ? C.red : C.accent, borderRadius: 2, transition: "width 1s linear" }} />
          </div>
        </div>
      </div>

      <div style={{ padding: "0 16px", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 16 }}>
        {[
          { label: "OPÉRATION", value: "TRANSIT",     color: C.accent },
          { label: "TERRAIN",   value: "SAINT-ALGIS", color: C.blue   },
          { label: "FACTION",   value: player.faction, color: fc      },
          { label: "MÉTÉO",     value: "11°C ☁️",     color: C.green  },
        ].map((s, i) => (
          <Card key={i} style={{ padding: "12px", borderLeft: `2px solid ${s.color}`, animation: `slideUp 0.3s ease ${i * 0.06}s both` }}>
            <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, letterSpacing: 1, marginBottom: 4 }}>{s.label}</div>
            <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 16, color: s.color }}>{s.value}</div>
          </Card>
        ))}
      </div>

      <div style={{ padding: "0 16px", marginBottom: 16 }}>
        <SectionTitle>Rappel sécurité</SectionTitle>
        <Card style={{ padding: "14px 16px", borderLeft: `2px solid ${C.red}` }}>
          <div style={{ fontFamily: "'Barlow'", fontSize: 13, color: C.text, lineHeight: 1.9 }}>
            ⚠️ Masque <strong>obligatoire</strong> en zone de jeu<br />
            🎯 HIT = bras levés + crier <strong>HIT</strong><br />
            🔇 Safe zone : arme basse, doigt hors détente
          </div>
        </Card>
      </div>

      <div style={{ padding: "0 16px" }}>
        <SectionTitle>Contexte opérationnel</SectionTitle>
        <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 4, overflow: "hidden" }}>
          <div style={{ padding: "10px 14px", background: C.red + "10", borderBottom: `1px solid ${C.red}30`, display: "flex", alignItems: "center", gap: 8 }}>
            <span>🔒</span>
            <span style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.red, letterSpacing: 1 }}>DOCUMENT CLASSIFIÉ — DGSE / DNRED INTERNATIONAL</span>
          </div>
          <div style={{ padding: "14px 16px", display: "flex", flexDirection: "column", gap: 12 }}>
            {LORE.split("\n\n").map((para, i) => (
              <p key={i} style={{ fontFamily: "'Barlow'", fontSize: 13, color: i === 0 ? C.text : C.muted, lineHeight: 1.8 }}>{para}</p>
            ))}
            <div style={{ padding: "10px 14px", borderLeft: `3px solid ${C.accent}`, background: C.accent + "08", borderRadius: 2 }}>
              <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14, color: C.accent, letterSpacing: 1 }}>"Sans lui, la DNRED est aveugle. Avec lui, le Cartel tombe."</div>
              <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, marginTop: 4 }}>— Rapport DGSE, J-72h</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

