// ── MISSION ───────────────────────────────────────────────────────────────────
function MissionScreen({ player, missions }) {
  const myMissions = missions[player.faction] || [];
  const fc = player.faction === "DNRED" ? C.drned : C.cartel;
  const priorityColor = p => ({ CRITIQUE: C.red, HAUTE: C.danger, MOYENNE: C.accent, BASSE: C.muted }[p] || C.muted);
  const statusInfo    = s => ({ secured: { label: "✅ ACCOMPLI", color: C.green }, pending: { label: "⏳ EN COURS", color: C.accent }, failed: { label: "❌ ÉCHOUÉ", color: C.red } }[s] || { label: s, color: C.muted });

  return (
    <div style={{ padding: "0 0 16px", animation: "fadeIn 0.4s ease" }}>
      <div style={{ background: fc + "10", borderBottom: `1px solid ${fc}30`, borderTop: `2px solid ${fc}`, padding: "16px 16px", marginBottom: 16 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, letterSpacing: 2, marginBottom: 4 }}>MISSION CONFIDENTIELLE</div>
        <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 20, color: fc, letterSpacing: 3 }}>{player.faction === "DNRED" ? "D.N.R.E.D" : "CARTEL DEL PASO"}</div>
        <div style={{ fontFamily: "'Barlow'", fontSize: 12, color: C.muted, marginTop: 4 }}>Classifié · visible uniquement par ta faction · mis à jour en temps réel</div>
      </div>
      {myMissions.length === 0
        ? <div style={{ padding: "40px 16px", textAlign: "center" }}><div style={{ fontSize: 32, marginBottom: 12 }}>📭</div><div style={{ fontFamily: "'Share Tech Mono'", fontSize: 11, color: C.muted }}>AUCUN OBJECTIF PUBLIÉ</div></div>
        : (
          <div style={{ padding: "0 16px", display: "flex", flexDirection: "column", gap: 10 }}>
            {myMissions.map((obj, i) => {
              const st = statusInfo(obj.status);
              return (
                <div key={obj.id} style={{ background: C.card, border: `1px solid ${obj.status === "secured" ? C.green + "40" : obj.status === "failed" ? C.red + "30" : C.border}`, borderLeft: `3px solid ${st.color}`, borderRadius: 4, padding: "14px 16px", animation: `slideUp 0.25s ease ${i * 0.08}s both` }}>
                  <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 8 }}>
                    <div style={{ width: 24, height: 24, borderRadius: 3, background: fc + "20", border: `1px solid ${fc}50`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Share Tech Mono'", fontSize: 10, color: fc, fontWeight: 700 }}>{i + 1}</div>
                    <span style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14 }}>{obj.label}</span>
                  </div>
                  <div style={{ fontFamily: "'Barlow'", fontSize: 12, color: C.muted, lineHeight: 1.5, marginBottom: 10 }}>{obj.desc}</div>
                  <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                    <Label color={priorityColor(obj.priority)}>PRIORITÉ {obj.priority}</Label>
                    <Label color={st.color}>{st.label}</Label>
                  </div>
                </div>
              );
            })}
          </div>
        )}
    </div>
  );
}

// ── SQUAD ─────────────────────────────────────────────────────────────────────
function SquadScreen({ player }) {
  const [squadCode, setSquadCode] = useState("");
  const [inputCode, setInputCode] = useState("");
  const [squadName, setSquadName] = useState("");
  const [members, setMembers]     = useState([]);
  const [mode, setMode]           = useState(null);
  const [error, setError]         = useState("");
  const fc = player.faction === "DNRED" ? C.drned : C.cartel;

  const createSquad = () => {
    if (!squadName.trim()) return setError("Donne un nom à ta squad");
    const code = Math.random().toString(36).substring(2, 7).toUpperCase();
    setSquadCode(code); setMembers([{ pseudo: player.pseudo, role: "Chef de squad" }]); setMode(null); setError("");
  };
  const joinSquad = () => {
    if (inputCode.length < 4) return setError("Code invalide");
    setSquadCode(inputCode.toUpperCase()); setSquadName("SQUAD " + inputCode.toUpperCase());
    setMembers([{ pseudo: "Viper", role: "Chef de squad" }, { pseudo: player.pseudo, role: "Membre" }]);
    setMode(null); setError("");
  };

  if (!squadCode && !mode) return (
    <div style={{ padding: 16, animation: "fadeIn 0.4s ease" }}>
      <SectionTitle color={fc}>Système de Squad</SectionTitle>
      <div style={{ fontFamily: "'Barlow'", fontSize: 13, color: C.muted, marginBottom: 24, lineHeight: 1.6 }}>Crée une squad ou rejoins-en une avec un code.</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        <button onClick={() => setMode("create")} style={{ padding: 16, background: fc + "18", border: `1px solid ${fc}60`, borderRadius: 6, color: fc, fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 16, letterSpacing: 2, cursor: "pointer" }}>➕ CRÉER UNE SQUAD</button>
        <button onClick={() => setMode("join")}   style={{ padding: 16, background: C.card, border: `1px solid ${C.border}`, borderRadius: 6, color: C.text, fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 16, letterSpacing: 2, cursor: "pointer" }}>🔗 REJOINDRE AVEC UN CODE</button>
      </div>
    </div>
  );

  if (mode === "create") return (
    <div style={{ padding: 16, animation: "fadeIn 0.3s ease" }}>
      <SectionTitle color={fc}>Créer une squad</SectionTitle>
      <div style={{ marginBottom: 12 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, letterSpacing: 1, marginBottom: 6 }}>NOM DE LA SQUAD</div>
        <input style={inputStyle} placeholder="Ex: Unité Delta" value={squadName} onChange={e => setSquadName(e.target.value)} />
      </div>
      {error && <div style={{ color: C.red, fontSize: 12, marginBottom: 10 }}>{error}</div>}
      <div style={{ display: "flex", gap: 8 }}>
        <Btn outline onClick={() => { setMode(null); setError(""); }} style={{ flex: 1 }}>← ANNULER</Btn>
        <Btn onClick={createSquad} color={fc} style={{ flex: 2 }}>CRÉER ✓</Btn>
      </div>
    </div>
  );

  if (mode === "join") return (
    <div style={{ padding: 16, animation: "fadeIn 0.3s ease" }}>
      <SectionTitle color={fc}>Rejoindre une squad</SectionTitle>
      <div style={{ marginBottom: 12 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, letterSpacing: 1, marginBottom: 6 }}>CODE</div>
        <input style={{ ...inputStyle, fontFamily: "'Share Tech Mono'", letterSpacing: 3, textTransform: "uppercase" }} placeholder="EX: A1B2C" value={inputCode} onChange={e => setInputCode(e.target.value.toUpperCase())} maxLength={6} />
      </div>
      {error && <div style={{ color: C.red, fontSize: 12, marginBottom: 10 }}>{error}</div>}
      <div style={{ display: "flex", gap: 8 }}>
        <Btn outline onClick={() => { setMode(null); setError(""); }} style={{ flex: 1 }}>← ANNULER</Btn>
        <Btn onClick={joinSquad} color={fc} style={{ flex: 2 }}>REJOINDRE ✓</Btn>
      </div>
    </div>
  );

  return (
    <div style={{ padding: "0 0 16px", animation: "fadeIn 0.4s ease" }}>
      <div style={{ background: fc + "12", borderBottom: `1px solid ${fc}30`, borderTop: `2px solid ${fc}`, padding: "16px 16px", marginBottom: 16 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, letterSpacing: 2, marginBottom: 4 }}>TA SQUAD</div>
        <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 22, color: fc, letterSpacing: 2, marginBottom: 10 }}>{squadName || "SQUAD " + squadCode}</div>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 10, color: C.muted, marginBottom: 6 }}>CODE D'INVITATION</div>
        <div style={{ display: "inline-block", background: C.card, border: `1px solid ${fc}60`, borderRadius: 4, padding: "8px 18px", fontFamily: "'Share Tech Mono'", fontSize: 26, color: fc, letterSpacing: 7 }}>{squadCode}</div>
      </div>
      <div style={{ padding: "0 16px" }}>
        <SectionTitle color={fc}>Membres ({members.length})</SectionTitle>
        {members.map((m, i) => (
          <Card key={i} style={{ padding: "12px 14px", display: "flex", alignItems: "center", gap: 10, marginBottom: 6, borderLeft: `2px solid ${m.pseudo === player.pseudo ? fc : C.border}` }}>
            <div style={{ width: 36, height: 36, borderRadius: 4, background: fc + "20", border: `1px solid ${fc}40`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14, color: fc }}>{m.pseudo[0].toUpperCase()}</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: "'Rajdhani'", fontWeight: 600, fontSize: 15, display: "flex", gap: 6, alignItems: "center" }}>{m.pseudo} {m.pseudo === player.pseudo && <Label color={C.green}>MOI</Label>}</div>
              <div style={{ fontFamily: "'Barlow'", fontSize: 11, color: C.muted }}>{m.role}</div>
            </div>
            {m.role === "Chef de squad" && <span style={{ fontSize: 16 }}>⭐</span>}
          </Card>
        ))}
        <button onClick={() => { setSquadCode(""); setSquadName(""); setMembers([]); setMode(null); }} style={{ width: "100%", marginTop: 10, padding: 10, background: "none", border: `1px solid ${C.red}40`, borderRadius: 4, color: C.red, fontFamily: "'Share Tech Mono'", fontSize: 11, letterSpacing: 1, cursor: "pointer" }}>QUITTER LA SQUAD</button>
      </div>
    </div>
  );
}

// ── BRIEFING ──────────────────────────────────────────────────────────────────
const OP_RULES = [
  { section: "SÉCURITÉ",            icon: "⚠️", color: C.red,    rules: ["Masque OBLIGATOIRE en zone de jeu à tout moment","FPS max : 350 en plein air, 280 en CQB","Safe zone : arme basse, doigt hors détente","HIT = bras levés + crier HIT clairement","Respect des arbitres — décision finale"] },
  { section: "GAMEPLAY",            icon: "🎯", color: C.accent, rules: ["Durée : OP 24h","Respawn : retour base en 3 minutes","Objectifs : consultez votre onglet MISSION","Pas de tir en zone safe","Communication radio autorisée"] },
  { section: "SCÉNARIO OP TRANSIT", icon: "📋", color: C.blue,   rules: ["DNRED : localiser et extraire Don Pipo avant que le Cartel ne l'exfiltre","Cartel Del Paso : défendre la base, neutraliser la DNRED et sécuriser l'otage","3 objectifs principaux par faction","Victoire : faction avec le plus d'objectifs accomplis à T+45","En cas d'égalité : l'équipe en possession de l'otage l'emporte"] },
];
function BriefingScreen() {
  const [expanded, setExpanded] = useState("SÉCURITÉ");
  return (
    <div style={{ padding: "0 0 16px", animation: "fadeIn 0.4s ease" }}>
      <div style={{ background: "#0d1117", borderBottom: `1px solid ${C.border}`, borderTop: `2px solid ${C.red}`, padding: "16px 16px", marginBottom: 16 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.red, letterSpacing: 2, marginBottom: 6 }}>⚠ BRIEFING OPÉRATIONNEL</div>
        <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 20, letterSpacing: 2, marginBottom: 4 }}>OP TRANSIT 2026</div>
        <div style={{ fontFamily: "'Barlow'", fontSize: 12, color: C.muted }}>Règles de sécurité et de gameplay — à lire avant de jouer.</div>
      </div>
      <div style={{ padding: "0 16px", display: "flex", flexDirection: "column", gap: 8 }}>
        {OP_RULES.map(section => (
          <div key={section.section} style={{ background: C.card, border: `1px solid ${expanded === section.section ? section.color + "50" : C.border}`, borderRadius: 4, overflow: "hidden" }}>
            <div onClick={() => setExpanded(expanded === section.section ? null : section.section)} style={{ display: "flex", alignItems: "center", gap: 10, padding: "14px 16px", cursor: "pointer", background: expanded === section.section ? section.color + "08" : "none" }}>
              <span style={{ fontSize: 18 }}>{section.icon}</span>
              <span style={{ flex: 1, fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 13, letterSpacing: 2, color: section.color }}>{section.section}</span>
              <span style={{ color: C.muted, fontSize: 11, fontFamily: "'Share Tech Mono'" }}>{expanded === section.section ? "▲" : "▼"}</span>
            </div>
            {expanded === section.section && (
              <div style={{ padding: "0 16px 14px", borderTop: `1px solid ${section.color}20` }}>
                {section.rules.map((rule, ri) => (
                  <div key={ri} style={{ display: "flex", gap: 10, padding: "8px 0", borderBottom: ri < section.rules.length - 1 ? `1px solid ${C.border}` : "none" }}>
                    <div style={{ color: section.color, fontSize: 9, fontFamily: "'Share Tech Mono'", paddingTop: 3, minWidth: 22 }}>{String(ri + 1).padStart(2, "0")}.</div>
                    <div style={{ fontFamily: "'Barlow'", fontSize: 13, color: C.text, lineHeight: 1.5 }}>{rule}</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
      <div style={{ margin: "14px 16px 0", background: C.green + "10", border: `1px solid ${C.green}40`, borderRadius: 4, padding: "12px 14px", display: "flex", gap: 10 }}>
        <span>✅</span><div style={{ fontFamily: "'Barlow'", fontSize: 12, color: C.green }}>Briefing confirmé. Bonne chance sur le terrain.</div>
      </div>
    </div>
  );
}

// ── ADMIN PANEL ───────────────────────────────────────────────────────────────
function AdminPanel({ missions, onMissionsUpdate, timerState, onTimerUpdate, players, onRemovePlayer, onChangePlayerFaction }) {
  const [tab, setTab]                 = useState("timer");
  const [activeFaction, setActiveFaction] = useState("DNRED");
  const [editingId, setEditingId]     = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [saving, setSaving]           = useState(false);
  const [toast, setToast]             = useState(null);
  const [announceText, setAnnounceText] = useState("");
  const emptyForm = { label: "", desc: "", priority: "HAUTE", status: "pending" };
  const [form, setForm] = useState(emptyForm);

  const fc      = activeFaction === "DNRED" ? C.drned : C.cartel;
  const current = missions[activeFaction] || [];
  const showToast = (msg, color = C.green) => { setToast({ msg, color }); setTimeout(() => setToast(null), 2500); };

  // TIMER
  let displayRemaining = timerState.remaining;
  if (timerState.running && timerState.startedAt) displayRemaining = Math.max(0, timerState.remaining - Math.floor((Date.now() - timerState.startedAt) / 1000));
  const dmm = String(Math.floor(displayRemaining / 60)).padStart(2, "0");
  const dss = String(displayRemaining % 60).padStart(2, "0");

  const timerStart = async () => { const t = { running: true, remaining: timerState.remaining, startedAt: Date.now() }; await sset(SK.timer, t); onTimerUpdate(t); };
  const timerPause = async () => { const t = { running: false, remaining: displayRemaining, startedAt: null }; await sset(SK.timer, t); onTimerUpdate(t); };
  const timerReset = async () => { await sset(SK.timer, DEFAULT_TIMER); onTimerUpdate(DEFAULT_TIMER); };
  const timerSet   = async m  => { const t = { running: false, remaining: m * 60, startedAt: null }; await sset(SK.timer, t); onTimerUpdate(t); };

  // ANNONCE
  const sendAnnounce = async () => { if (!announceText.trim()) return; await sset(SK.announce, { text: announceText.trim(), at: Date.now() }); setAnnounceText(""); showToast("📢 Annonce envoyée !"); };
  const clearAnnounce = async () => { await sset(SK.announce, { text: "", at: null }); showToast("Annonce effacée", C.muted); };

  // MISSIONS
  const saveMissionsData = async updated => { setSaving(true); await sset(SK.missions, updated); onMissionsUpdate(updated); setSaving(false); };
  const startEdit = obj => { setEditingId(obj.id); setForm({ label: obj.label, desc: obj.desc, priority: obj.priority, status: obj.status }); setShowAddForm(false); };
  const saveEdit  = async () => { if (!form.label.trim()) return; await saveMissionsData({ ...missions, [activeFaction]: current.map(o => o.id === editingId ? { ...o, ...form } : o) }); setEditingId(null); showToast("✅ Mis à jour"); };
  const deleteObj = async id => { await saveMissionsData({ ...missions, [activeFaction]: current.filter(o => o.id !== id) }); showToast("🗑 Supprimé", C.red); };
  const addObj    = async () => { if (!form.label.trim()) return; const nid = activeFaction[0] + Date.now().toString(36).slice(-4).toUpperCase(); await saveMissionsData({ ...missions, [activeFaction]: [...current, { id: nid, ...form }] }); setShowAddForm(false); setForm(emptyForm); showToast("✅ Ajouté"); };

  const priorityColor = p => ({ CRITIQUE: C.red, HAUTE: C.danger, MOYENNE: C.accent, BASSE: C.muted }[p] || C.muted);
  const statusInfo    = s => ({ secured: { label: "✅ ACCOMPLI", color: C.green }, pending: { label: "⏳ EN COURS", color: C.accent }, failed: { label: "❌ ÉCHOUÉ", color: C.red } }[s] || {});

  const MissionForm = ({ onSave, onCancel, saveLabel }) => (
    <div style={{ background: C.surface, border: `1px solid ${fc}50`, borderRadius: 6, padding: 14, marginBottom: 10 }}>
      <div style={{ marginBottom: 10 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, marginBottom: 5 }}>TITRE</div>
        <input style={inputStyle} value={form.label} onChange={e => setForm(f => ({ ...f, label: e.target.value }))} placeholder="Ex: Sécuriser le point Alpha" />
      </div>
      <div style={{ marginBottom: 10 }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, marginBottom: 5 }}>DESCRIPTION</div>
        <textarea style={{ ...inputStyle, minHeight: 70, resize: "vertical", lineHeight: 1.5 }} value={form.desc} onChange={e => setForm(f => ({ ...f, desc: e.target.value }))} />
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 12 }}>
        <div>
          <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, marginBottom: 5 }}>PRIORITÉ</div>
          <select style={selectStyle} value={form.priority} onChange={e => setForm(f => ({ ...f, priority: e.target.value }))}>{PRIORITIES.map(p => <option key={p}>{p}</option>)}</select>
        </div>
        <div>
          <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, marginBottom: 5 }}>STATUT</div>
          <select style={selectStyle} value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))}>{STATUSES.map(s => <option key={s.value} value={s.value}>{s.label}</option>)}</select>
        </div>
      </div>
      <div style={{ display: "flex", gap: 8 }}>
        <Btn outline onClick={onCancel} style={{ flex: 1 }}>ANNULER</Btn>
        <Btn onClick={onSave} color={fc} disabled={!form.label.trim() || saving} style={{ flex: 2 }}>{saving ? "…" : saveLabel}</Btn>
      </div>
    </div>
  );

  const TABS = [{ id: "timer", label: "⏱ CHRONO" }, { id: "missions", label: "🎯 MISSIONS" }, { id: "players", label: "👥 JOUEURS" }, { id: "comms", label: "📢 COMMS" }];

  return (
    <div style={{ padding: "0 0 16px", animation: "fadeIn 0.4s ease", position: "relative" }}>
      {toast && <Toast msg={toast.msg} color={toast.color} />}

      <div style={{ background: C.admin + "10", borderBottom: `1px solid ${C.admin}30`, borderTop: `2px solid ${C.admin}`, padding: "14px 16px" }}>
        <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.admin, letterSpacing: 2, marginBottom: 4 }}>⭐ PANNEAU ADMINISTRATEUR</div>
        <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 18, letterSpacing: 2 }}>GESTION OP TRANSIT</div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", background: C.surface, borderBottom: `1px solid ${C.border}`, marginBottom: 16 }}>
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)} style={{ padding: "10px 4px", background: tab === t.id ? C.admin + "15" : "none", border: "none", borderBottom: `2px solid ${tab === t.id ? C.admin : "transparent"}`, color: tab === t.id ? C.admin : C.muted, fontFamily: "'Share Tech Mono'", fontSize: 9, cursor: "pointer" }}>{t.label}</button>
        ))}
      </div>

      {/* CHRONO */}
      {tab === "timer" && (
        <div style={{ padding: "0 16px", animation: "fadeIn 0.3s ease" }}>
          <SectionTitle color={C.admin}>Contrôle du chronomètre</SectionTitle>
          <div style={{ background: C.card, border: `1px solid ${C.border}`, borderRadius: 6, padding: "24px 16px", textAlign: "center", marginBottom: 16 }}>
            <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 56, color: timerState.running ? C.accent : C.muted, letterSpacing: 8, lineHeight: 1 }}>{dmm}:{dss}</div>
            <div style={{ fontFamily: "'Barlow'", fontSize: 11, color: C.muted, marginTop: 6 }}>{timerState.running ? "🟢 EN COURS — visible par tous" : "⏸ EN PAUSE"}</div>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
            {!timerState.running
              ? <Btn onClick={timerStart} color={C.green} style={{ gridColumn: "span 2" }}>▶ DÉMARRER</Btn>
              : <Btn onClick={timerPause} color={C.danger} style={{ gridColumn: "span 2" }}>⏸ PAUSE</Btn>}
            <Btn onClick={timerReset} outline>↺ RESET</Btn>
          </div>
          <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, letterSpacing: 1, marginBottom: 8 }}>DURÉE PRÉDÉFINIE</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 6 }}>
            {[15, 30, 45, 60].map(min => (
              <button key={min} onClick={() => timerSet(min)} style={{ padding: "10px 6px", background: timerState.remaining === min * 60 && !timerState.running ? C.admin + "20" : C.surface, border: `1px solid ${timerState.remaining === min * 60 && !timerState.running ? C.admin : C.border}`, borderRadius: 4, color: timerState.remaining === min * 60 && !timerState.running ? C.admin : C.muted, fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 16, cursor: "pointer" }}>
                {min}<span style={{ fontSize: 10 }}>m</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* MISSIONS */}
      {tab === "missions" && (
        <div style={{ padding: "0 16px", animation: "fadeIn 0.3s ease" }}>
          <div style={{ display: "flex", background: C.surface, borderRadius: 4, border: `1px solid ${C.border}`, overflow: "hidden", marginBottom: 14 }}>
            {["DNRED", "CARTEL"].map(f => (
              <button key={f} onClick={() => { setActiveFaction(f); setEditingId(null); setShowAddForm(false); setForm(emptyForm); }} style={{ flex: 1, padding: "10px", background: activeFaction === f ? (f === "DNRED" ? C.drned : C.cartel) : "none", border: "none", color: activeFaction === f ? "#fff" : C.muted, fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 13, letterSpacing: 2, cursor: "pointer" }}>
                {f === "DNRED" ? "🛡 D.N.R.E.D" : "☠️ CARTEL DEL PASO"}
              </button>
            ))}
          </div>

          {!showAddForm && !editingId && (
            <button onClick={() => { setShowAddForm(true); setForm(emptyForm); }} style={{ width: "100%", padding: 11, marginBottom: 14, background: fc + "12", border: `1px dashed ${fc}60`, borderRadius: 4, color: fc, fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>＋ AJOUTER UN OBJECTIF</button>
          )}
          {showAddForm && <MissionForm onSave={addObj} onCancel={() => { setShowAddForm(false); setForm(emptyForm); }} saveLabel="AJOUTER ✓" />}
          {current.length === 0 && !showAddForm && (
            <div style={{ textAlign: "center", padding: "30px 0" }}><div style={{ fontSize: 28, marginBottom: 8 }}>📭</div><div style={{ fontFamily: "'Share Tech Mono'", fontSize: 11, color: C.muted }}>AUCUN OBJECTIF</div></div>
          )}
          {current.map((obj, i) => {
            const st = statusInfo(obj.status);
            return (
              <div key={obj.id} style={{ marginBottom: 8 }}>
                {editingId === obj.id
                  ? <MissionForm onSave={saveEdit} onCancel={() => { setEditingId(null); setForm(emptyForm); }} saveLabel="ENREGISTRER ✓" />
                  : (
                    <div style={{ background: C.card, border: `1px solid ${C.border}`, borderLeft: `3px solid ${st.color || C.muted}`, borderRadius: 4, padding: "12px 14px" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 6 }}>
                        <span style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14, flex: 1, marginRight: 8 }}>{obj.label}</span>
                        <div style={{ display: "flex", gap: 6 }}>
                          <button onClick={() => startEdit(obj)} style={{ background: C.accent + "18", border: `1px solid ${C.accent}40`, borderRadius: 3, padding: "4px 8px", color: C.accent, fontSize: 10, cursor: "pointer" }}>✏️</button>
                          <button onClick={() => deleteObj(obj.id)} style={{ background: C.red + "18", border: `1px solid ${C.red}40`, borderRadius: 3, padding: "4px 8px", color: C.red, fontSize: 10, cursor: "pointer" }}>🗑</button>
                        </div>
                      </div>
                      {obj.desc && <div style={{ fontFamily: "'Barlow'", fontSize: 11, color: C.muted, lineHeight: 1.5, marginBottom: 8 }}>{obj.desc}</div>}
                      <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
                        <Label color={priorityColor(obj.priority)}>{obj.priority}</Label>
                        <Label color={st.color}>{st.label}</Label>
                      </div>
                    </div>
                  )}
              </div>
            );
          })}
        </div>
      )}

      {/* JOUEURS */}
      {tab === "players" && (
        <div style={{ padding: "0 16px", animation: "fadeIn 0.3s ease" }}>
          <SectionTitle color={C.admin}>Joueurs inscrits ({players.length})</SectionTitle>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 16 }}>
            {["DNRED", "CARTEL"].map(f => (
              <div key={f} style={{ background: C.card, border: `1px solid ${C.border}`, borderLeft: `2px solid ${f === "DNRED" ? C.drned : C.cartel}`, borderRadius: 4, padding: "10px 12px", textAlign: "center" }}>
                <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 24, color: f === "DNRED" ? C.drned : C.cartel }}>{players.filter(p => p.faction === f).length}</div>
                <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted }}>{f === "DNRED" ? "D.N.R.E.D" : "CARTEL DEL PASO"}</div>
              </div>
            ))}
          </div>
          {players.length === 0
            ? <div style={{ textAlign: "center", padding: "30px 0" }}><div style={{ fontSize: 28, marginBottom: 8 }}>👥</div><div style={{ fontFamily: "'Share Tech Mono'", fontSize: 11, color: C.muted }}>AUCUN JOUEUR</div></div>
            : (
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {players.map((p, i) => {
                  const pfc = p.faction === "DNRED" ? C.drned : C.cartel;
                  return (
                    <div key={p.id} style={{ background: C.card, border: `1px solid ${C.border}`, borderLeft: `2px solid ${pfc}`, borderRadius: 4, padding: "10px 12px", display: "flex", alignItems: "center", gap: 10 }}>
                      <div style={{ width: 32, height: 32, borderRadius: 4, background: pfc + "20", border: `1px solid ${pfc}40`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 13, color: pfc }}>{p.pseudo[0].toUpperCase()}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontFamily: "'Rajdhani'", fontWeight: 600, fontSize: 14, display: "flex", gap: 5, alignItems: "center" }}>
                          {p.pseudo} {p.isAdmin && <Label color={C.admin}>ADMIN</Label>}
                        </div>
                        <div style={{ fontFamily: "'Barlow'", fontSize: 11, color: C.muted }}>{p.nom || "—"}</div>
                      </div>
                      <button onClick={() => onChangePlayerFaction(p.id)} style={{ background: pfc + "15", border: `1px solid ${pfc}40`, borderRadius: 3, padding: "4px 8px", color: pfc, fontFamily: "'Share Tech Mono'", fontSize: 9, cursor: "pointer" }}>
                        {p.faction === "DNRED" ? "→ CARTEL" : "→ DNRED"}
                      </button>
                      <button onClick={() => onRemovePlayer(p.id)} style={{ background: C.red + "15", border: `1px solid ${C.red}30`, borderRadius: 3, padding: "4px 8px", color: C.red, fontSize: 10, cursor: "pointer" }}>✕</button>
                    </div>
                  );
                })}
              </div>
            )}
        </div>
      )}

      {/* COMMS */}
      {tab === "comms" && (
        <div style={{ padding: "0 16px", animation: "fadeIn 0.3s ease" }}>
          <SectionTitle color={C.admin}>Annonce broadcast</SectionTitle>
          <div style={{ fontFamily: "'Barlow'", fontSize: 13, color: C.muted, marginBottom: 16, lineHeight: 1.6 }}>
            S'affiche immédiatement sur l'écran de tous les joueurs connectés.
          </div>
          <textarea style={{ ...inputStyle, minHeight: 90, resize: "vertical", lineHeight: 1.6, marginBottom: 10 }} placeholder="Ex: Respawn ouvert · Revenez en base · 5 minutes restantes !" value={announceText} onChange={e => setAnnounceText(e.target.value)} />
          <div style={{ display: "flex", gap: 8, marginBottom: 20 }}>
            <Btn onClick={sendAnnounce} color={C.danger} disabled={!announceText.trim()} style={{ flex: 2 }}>📢 ENVOYER À TOUS</Btn>
            <Btn onClick={clearAnnounce} outline style={{ flex: 1 }}>✕ EFFACER</Btn>
          </div>
          {announceText.trim() && (
            <div>
              <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.muted, letterSpacing: 1, marginBottom: 8 }}>APERÇU</div>
              <div style={{ background: C.danger + "15", border: `1px solid ${C.danger}50`, borderRadius: 6, padding: "10px 14px", display: "flex", alignItems: "center", gap: 10 }}>
                <span style={{ fontSize: 16 }}>📢</span>
                <div>
                  <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.danger, letterSpacing: 1, marginBottom: 2 }}>ANNONCE ADMIN</div>
                  <div style={{ fontFamily: "'Barlow'", fontSize: 13, color: C.text }}>{announceText}</div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── MAIN APP ──────────────────────────────────────────────────────────────────
const NAV_PLAYER = [{ id: "home", icon: "🏠", label: "ACCUEIL" }, { id: "map", icon: "🗺", label: "CARTE" }, { id: "mission", icon: "🎯", label: "MISSION" }, { id: "squad", icon: "👥", label: "SQUAD" }, { id: "briefing", icon: "📋", label: "RÈGLES" }];
const NAV_ADMIN  = [{ id: "home", icon: "🏠", label: "ACCUEIL" }, { id: "map", icon: "🗺", label: "CARTE"   }, { id: "admin",   icon: "⭐", label: "ADMIN"   }, { id: "squad", icon: "👥", label: "SQUAD"   }, { id: "briefing", icon: "📋", label: "RÈGLES"  }];

export default function App() {
  const [player, setPlayer]           = useState(null);
  const [screen, setScreen]           = useState("home");
  const [missions, setMissions]       = useState(DEFAULT_MISSIONS);
  const [timerState, setTimerState]   = useState(DEFAULT_TIMER);
  const [players, setPlayers]         = useState([]);
  const [announce, setAnnounce]       = useState(null);
  const [dismissedAt, setDismissedAt] = useState(null);
  const [showProfil, setShowProfil]   = useState(false);
  const [loading, setLoading]         = useState(true);
  const [, tick]                      = useState(0);

  // Restore session
  useEffect(() => { const s = loadSession(); if (s) setPlayer(s); }, []);

  // Initial load
  useEffect(() => {
    Promise.all([
      sget(SK.missions).then(m => m && setMissions(m)),
      sget(SK.timer).then(t => t && setTimerState(t)),
      sget(SK.players).then(p => p && setPlayers(p)),
      sget(SK.announce).then(a => a && setAnnounce(a)),
    ]).finally(() => setLoading(false));
  }, []);

  // Poll every 8s
  useEffect(() => {
    if (!player) return;
    const id = setInterval(async () => {
      const [m, t, p, a] = await Promise.all([sget(SK.missions), sget(SK.timer), sget(SK.players), sget(SK.announce)]);
      if (m) setMissions(m);
      if (t) setTimerState(t);
      if (p) setPlayers(p);
      if (a) setAnnounce(a);
    }, 8000);
    return () => clearInterval(id);
  }, [player]);

  // Local tick for smooth timer
  useEffect(() => {
    if (!timerState.running) return;
    const id = setInterval(() => tick(x => x + 1), 1000);
    return () => clearInterval(id);
  }, [timerState.running, timerState.startedAt]);

  const handleRegister = async p => {
    const np = { ...p, id: Date.now().toString(36) };
    setPlayer(np); saveSession(np); setScreen("home");
    const cur = await sget(SK.players) || [];
    await sset(SK.players, [...cur, np]);
    setPlayers(prev => [...prev, np]);
  };

  const handleLogout = async () => {
    const cur = await sget(SK.players) || [];
    await sset(SK.players, cur.filter(p => p.id !== player.id));
    clearSession(); setPlayer(null); setScreen("home"); setShowProfil(false);
  };

  const handleRemovePlayer = async id => {
    const u = players.filter(p => p.id !== id); await sset(SK.players, u); setPlayers(u);
  };

  const handleChangePlayerFaction = async id => {
    const u = players.map(p => p.id === id ? { ...p, faction: p.faction === "DNRED" ? "CARTEL" : "DNRED" } : p);
    await sset(SK.players, u); setPlayers(u);
  };

  const fc  = player ? (player.faction === "DNRED" ? C.drned : C.cartel) : C.accent;
  const NAV = player?.isAdmin ? NAV_ADMIN : NAV_PLAYER;
  const showAnnounce = announce?.text && announce.at !== dismissedAt;

  if (loading) return (
    <>
      <Head>
        <title>OP Transit 2026</title>
        <meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1" />
        <meta name="theme-color" content="#0a0c0e" />
        <meta name="mobile-web-app-capable" content="yes" />
        <meta name="apple-mobile-web-app-capable" content="yes" />
        <meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
      </Head>
      <style>{FONT}</style>
    <div style={{ maxWidth: 430, margin: "0 auto", minHeight: "100vh", background: C.bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ fontFamily: "'Share Tech Mono'", color: C.muted, fontSize: 12, letterSpacing: 2, animation: "shimmer 1.2s infinite" }}>CHARGEMENT…</div>
    </div></>
  );

  if (!player) return (
    <>
      <Head>
        <title>OP Transit 2026</title>
        <meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1" />
        <meta name="theme-color" content="#0a0c0e" />
        <meta name="mobile-web-app-capable" content="yes" />
        <meta name="apple-mobile-web-app-capable" content="yes" />
        <meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
      </Head>
      <style>{FONT}</style>
    <div style={{ maxWidth: 430, margin: "0 auto", minHeight: "100vh", background: C.bg }}>
      <InscriptionScreen onRegister={handleRegister} />
    </div></>
  );

  const screens = {
    home:     () => <HomeScreen player={player} timerState={timerState} />,
    map:      () => <MapScreen />,
    mission:  () => <MissionScreen player={player} missions={missions} />,
    admin:    () => <AdminPanel missions={missions} onMissionsUpdate={setMissions} timerState={timerState} onTimerUpdate={setTimerState} players={players} onRemovePlayer={handleRemovePlayer} onChangePlayerFaction={handleChangePlayerFaction} />,
    squad:    () => <SquadScreen player={player} />,
    briefing: () => <BriefingScreen />,
  };

  return (
    <>
      <Head>
        <title>OP Transit 2026</title>
        <meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1" />
        <meta name="theme-color" content="#0a0c0e" />
        <meta name="mobile-web-app-capable" content="yes" />
        <meta name="apple-mobile-web-app-capable" content="yes" />
        <meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
      </Head>
      <style>{FONT}</style>
    <div style={{ maxWidth: 430, margin: "0 auto", minHeight: "100vh", background: C.bg, display: "flex", flexDirection: "column" }}>

      {showProfil && <ProfilDrawer player={player} fc={fc} onClose={() => setShowProfil(false)} onLogout={handleLogout} />}

      {/* TOP BAR */}
      <div style={{ background: C.surface, borderBottom: `1px solid ${C.border}`, padding: "10px 16px", display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 100 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ width: 28, height: 28, background: fc + "22", border: `1px solid ${fc}`, borderRadius: 3, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 11, color: fc }}>OP</div>
          <div>
            <div style={{ fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 14, letterSpacing: 2, lineHeight: 1 }}>TRANSIT</div>
            <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 8, color: C.muted, letterSpacing: 1 }}>COMPANION v7</div>
          </div>
        </div>
        <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
          <div style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: C.green }}>
            <span style={{ animation: "blink 1s infinite", display: "inline-block", marginRight: 3, fontSize: 7 }}>●</span>
            {new Date().toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" })}
          </div>
          <button onClick={() => setShowProfil(true)} style={{ display: "flex", alignItems: "center", gap: 6, background: fc + "15", border: `1px solid ${fc}50`, borderRadius: 20, padding: "4px 10px 4px 6px", cursor: "pointer" }}>
            <div style={{ width: 22, height: 22, borderRadius: "50%", background: fc + "30", border: `1px solid ${fc}`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Rajdhani'", fontWeight: 700, fontSize: 11, color: fc }}>{player.pseudo[0].toUpperCase()}</div>
            <span style={{ fontFamily: "'Share Tech Mono'", fontSize: 9, color: fc, letterSpacing: 1 }}>
              {player.pseudo.length > 8 ? player.pseudo.substring(0, 8).toUpperCase() + "…" : player.pseudo.toUpperCase()}
            </span>
            {player.isAdmin && <span style={{ fontSize: 10 }}>⭐</span>}
          </button>
        </div>
      </div>

      {/* ANNONCE */}
      {showAnnounce && <AnnounceBanner announce={announce} onDismiss={() => setDismissedAt(announce.at)} />}

      {/* CONTENT */}
      <div style={{ flex: 1, overflowY: "auto" }}>
        {screens[screen] ? screens[screen]() : null}
      </div>

      {/* BOTTOM NAV */}
      <div style={{ background: C.surface, borderTop: `1px solid ${C.border}`, display: "flex", position: "sticky", bottom: 0, zIndex: 100 }}>
        {NAV.map(n => {
          const active = screen === n.id;
          const color  = n.id === "admin" ? C.admin : fc;
          return (
            <button key={n.id} onClick={() => setScreen(n.id)} style={{ flex: 1, padding: "10px 4px 8px", background: active ? color + "12" : "none", border: "none", borderTop: `2px solid ${active ? color : "transparent"}`, display: "flex", flexDirection: "column", alignItems: "center", gap: 3, cursor: "pointer" }}>
              <span style={{ fontSize: 15 }}>{n.icon}</span>
              <span style={{ fontFamily: "'Share Tech Mono'", fontSize: 7, letterSpacing: 0.5, color: active ? color : C.muted }}>{n.label}</span>
            </button>
          );
        })}
      </div>
    </div></>
  );
}
